const digits = String(Date.now()).slice(-10);
const ownerChatId = '91' + digits;
const tag = 'zz' + String(Date.now()).slice(-6);
return [{
  json: {
    tag,
    owner_chat_id: ownerChatId,
    production_owner_chat_id: '919148969183',
    store_name: 'ZZ Owner ' + tag,
    upi_id: 'zz' + tag + '@upi',
    delivery_area: 'Test Area ' + tag,
    operating_hours: '8am-10pm',
    manual_message: tag + ' milk 40 20\n' + tag + ' rice 60 25',
    direct_update_message: tag + ' milk stock 18',
    promo_message: '10% off ' + tag + ' rice',
    test_mode: true,
  },
}];

const seed = $('Seed Owner Inputs').first().json || {};
const start = $('Run Setup Start').first().json || {};
const saveName = $('Run Save Store Name').first().json || {};
const saveUpi = $('Run Save UPI').first().json || {};
const saveArea = $('Run Save Area').first().json || {};
const saveHours = $('Run Save Hours').first().json || {};
const bootstrap = $('Run Bootstrap Selection').first().json || {};
const store = $('Lookup Test Store').first().json || {};
const manualPreview = $('Run Manual Preview').first().json || {};
const manualApply = $('Run Manual Confirm').first().json || {};
const directUpdate = $('Run Direct Update').first().json || {};
const promoPreview = $('Run Promo Preview').first().json || {};
const promoApply = $('Run Promo Confirm').first().json || {};
const xlsxPreview = $('Run XLSX Preview').first().json || {};
const xlsxApply = $('Run XLSX Confirm').first().json || {};
const bulkSheetPreview = $('Run Bulk Sheet Preview').first().json || {};
const bulkSheetApply = $('Run Bulk Sheet Confirm').first().json || {};
const goodImagePreview = $('Run Good Image Preview').first().json || {};
const goodImageApply = $('Run Good Image Confirm').first().json || {};
const badImagePreview = $('Run Bad Image Preview').first().json || {};
const dbRows = $('Verify Owner DB State').all().map((item) => item.json || {});
const hasButton = (resp, prefix) => Array.isArray(resp.buttons) && resp.buttons.some((button) => String(button.id || '').startsWith(prefix));
const byKind = (kind) => dbRows.find((row) => row.kind === kind) || {};
return [{
  json: {
    owner_chat_id: seed.owner_chat_id,
    store_id: Number(store.store_id || 0),
    responses: {
      setup_start: String(start.body_text || ''),
      save_name: String(saveName.body_text || ''),
      save_upi: String(saveUpi.body_text || ''),
      save_area: String(saveArea.body_text || ''),
      save_hours: String(saveHours.body_text || ''),
      bootstrap: String(bootstrap.body_text || ''),
      manual_preview: String(manualPreview.body_text || ''),
      manual_apply: String(manualApply.body_text || ''),
      direct_update: String(directUpdate.body_text || ''),
      promo_preview: String(promoPreview.body_text || ''),
      promo_apply: String(promoApply.body_text || ''),
      xlsx_preview: String(xlsxPreview.body_text || ''),
      xlsx_apply: String(xlsxApply.body_text || ''),
      bulk_sheet_preview: String(bulkSheetPreview.body_text || ''),
      bulk_sheet_apply: String(bulkSheetApply.body_text || ''),
      good_image_preview: String(goodImagePreview.body_text || ''),
      good_image_apply: String(goodImageApply.body_text || ''),
      bad_image_preview: String(badImagePreview.body_text || ''),
    },
    checks: {
      start_asks_store_name: /store name/i.test(String(start.body_text || '')),
      name_asks_upi: /upi/i.test(String(saveName.body_text || '')),
      upi_asks_area: /delivery area/i.test(String(saveUpi.body_text || '')),
      area_asks_hours: /operating hours/i.test(String(saveArea.body_text || '')),
      hours_has_bootstrap_buttons: Array.isArray(saveHours.buttons) && saveHours.buttons.length >= 2,
      bootstrap_completes_setup: /setup complete/i.test(String(bootstrap.body_text || '')),
      store_row_created: /zz owner/i.test(String(byKind('store').label || '').toLowerCase()),
      store_id_present: Number(store.store_id || 0) > 0,
      store_fields_persisted: /@upi/i.test(String(byKind('store').val1 || '')) && /test area/i.test(String(byKind('store').val2 || '').toLowerCase()) && /8am-10pm/i.test(String(byKind('store').val3 || '')),
      manual_preview_has_confirm: hasButton(manualPreview, 'owner_inv_confirm__'),
      manual_apply_ok: /catalog updated/i.test(String(manualApply.body_text || '')),
      direct_update_ok: /updated|stock/i.test(String(directUpdate.body_text || '')),
      promo_preview_has_confirm: hasButton(promoPreview, 'owner_promo_confirm__'),
      promo_apply_ok: /discount saved/i.test(String(promoApply.body_text || '')),
      xlsx_preview_has_apply: hasButton(xlsxPreview, 'owner_bulk_apply__'),
      xlsx_apply_ok: /bulk import applied/i.test(String(xlsxApply.body_text || '')),
      bulk_sheet_preview_has_apply: hasButton(bulkSheetPreview, 'owner_bulk_apply__'),
      bulk_sheet_apply_ok: /bulk import applied/i.test(String(bulkSheetApply.body_text || '')),
      good_image_preview_has_apply: hasButton(goodImagePreview, 'owner_bulk_apply__'),
      good_image_apply_ok: /bulk import applied/i.test(String(goodImageApply.body_text || '')),
      bad_image_blocked: !hasButton(badImagePreview, 'owner_bulk_apply__') && /no valid rows|could not stage|too large|OCR/i.test(String(badImagePreview.body_text || '')),
      tag_inventory_at_least_two: Number(byKind('inventory_tag_count').label || 0) >= 2,
      bulk_sheet_rows_applied: Number(byKind('bulk_sheet_inventory_count').label || 0) >= 600,
      promo_count_at_least_one: Number(byKind('promo_tag_count').label || 0) >= 1,
      session_rows_recorded: Number(byKind('session_count').label || 0) >= 4,
      import_jobs_recorded: Number(byKind('import_job_count').label || 0) >= 3,
      import_rows_recorded: Number(byKind('import_row_count').label || 0) >= 620,
    },
    db_rows: dbRows,
  },
}];
